const express = require('express');
const { createProxyMiddleware } = require('http-proxy-middleware');
const crypto = require('crypto');
const app = express();

const API_KEYS = new Set();
const BACKEND_SERVICES = new Map();

// Load API keys from environment (in production, use secure secret management)
const loadApiKeys = () => {
  const keys = process.env.API_KEYS?.split(',') || [];
  keys.forEach(key => API_KEYS.add(key.trim()));
};

// Load backend services from environment
const loadBackendServices = () => {
  const services = process.env.BACKEND_SERVICES?.split(',') || [];
  services.forEach(service => {
    const [name, url] = service.split('=');
    if (name && url) {
      BACKEND_SERVICES.set(name.trim(), url.trim());
    }
  });
};

loadApiKeys();
loadBackendServices();

// Middleware to validate API key
const validateApiKey = (req, res, next) => {
  const apiKey = req.query.api_key;
  
  if (!apiKey) {
    return res.status(401).json({ error: 'API key required' });
  }
  
  if (!API_KEYS.has(apiKey)) {
    return res.status(403).json({ error: 'Invalid API key' });
  }
  
  req.validatedApiKey = apiKey;
  next();
};

// Middleware to log requests securely
const requestLogger = (req, res, next) => {
  const timestamp = new Date().toISOString();
  const ip = req.ip || req.connection.remoteAddress;
  const method = req.method;
  const url = req.url;
  const userAgent = req.get('User-Agent') || '';
  
  // Log request details without exposing sensitive data
  console.log(JSON.stringify({
    timestamp,
    ip,
    method,
    url,
    userAgent,
    // Log only the service name, not the API key
    service: req.params.service || 'unknown'
  }));
  
  next();
};

// Middleware to sanitize and validate service name
const validateService = (req, res, next) => {
  const serviceName = req.params.service;
  
  if (!serviceName) {
    return res.status(400).json({ error: 'Service name required' });
  }
  
  // Validate service name against allowed list
  if (!BACKEND_SERVICES.has(serviceName)) {
    return res.status(404).json({ error: 'Service not found' });
  }
  
  req.serviceUrl = BACKEND_SERVICES.get(serviceName);
  next();
};

// Middleware to forward API key in headers
const forwardApiKey = (req, res, next) => {
  // Remove api_key from query params to prevent logging
  const { api_key, ...cleanQuery } = req.query;
  req.query = cleanQuery;
  
  next();
};

// Create proxy middleware with secure configuration
const createSecureProxy = (target) => {
  return createProxyMiddleware({
    target,
    changeOrigin: true,
    secure: true,
    logLevel: 'warn',
    onProxyReq: (proxyReq, req, res) => {
      // Forward API key in headers
      if (req.validatedApiKey) {
        proxyReq.setHeader('X-API-Key', req.validatedApiKey);
      }
      
      // Remove sensitive headers that might be injected
      proxyReq.removeHeader('authorization');
      proxyReq.removeHeader('x-api-key');
      
      // Log proxy request (without sensitive data)
      console.log(JSON.stringify({
        timestamp: new Date().toISOString(),
        action: 'proxy_request',
        target: target,
        method: proxyReq.method,
        path: proxyReq.path
      }));
    },
    onProxyRes: (proxyRes, req, res) => {
      // Log proxy response
      console.log(JSON.stringify({
        timestamp: new Date().toISOString(),
        action: 'proxy_response',
        target: target,
        statusCode: proxyRes.statusCode
      }));
    }
  });
};

// API routes
app.use('/api/:service/*', validateApiKey, validateService, forwardApiKey, requestLogger, createSecureProxy);

// Health check endpoint
app.get('/health', (req, res) => {
  res.json({ status: 'OK', timestamp: new Date().toISOString() });
});

// Error handling middleware
app.use((err, req, res, next) => {
  console.error('API Gateway Error:', err);
  res.status(500).json({ error: 'Internal server error' });
});

// 404 handler
app.use('*', (req, res) => {
  res.status(404).json({ error: 'Route not found' });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`API Gateway running on port ${PORT}`);
});

module.exports = app;